pub(in crate::cli::batch) fn dispatch_gc(ctx: &BatchContext) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_gc").entered();

    let file_set = ctx.file_set()?;
    let (stale_count, missing_count) = match ctx.store().count_stale_files(&file_set, &ctx.root) {
        Ok(counts) => counts,
        Err(e) => {
            tracing::warn!(error = %e, "Failed to count stale files");
            (0, 0)
        }
    };

    let prune = ctx
        .store()
        .prune_all(&file_set, &ctx.root)
        .context("Failed to prune stale entries from index")?;

    let output = crate::cli::commands::GcOutput {
        stale_files: stale_count as usize,
        missing_files: missing_count as usize,
        pruned_chunks: prune.pruned_chunks as usize,
        pruned_calls: prune.pruned_calls as usize,
        pruned_type_edges: prune.pruned_type_edges as usize,
        pruned_summaries: prune.pruned_summaries,
        hnsw_rebuilt: false,
        hnsw_vectors: None,
    };
    Ok(serde_json::to_value(&output)?)
}

pub(in crate::cli::batch) fn dispatch_gc(ctx: &BatchContext) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_gc").entered();

    let file_set = ctx.file_set()?;
    let (stale_count, missing_count) = match ctx.store().count_stale_files(&file_set, &ctx.root) {
        Ok(counts) => counts,
        Err(e) => {
            tracing::warn!(error = %e, "Failed to count stale files");
            (0, 0)
        }
    };

    let prune = ctx
        .store()
        .prune_all(&file_set, &ctx.root)
        .context("Failed to prune stale entries from index")?;

    let output = crate::cli::commands::GcOutput {
        stale_files: stale_count as usize,
        missing_files: missing_count as usize,
        pruned_chunks: prune.pruned_chunks as usize,
        pruned_calls: prune.pruned_calls as usize,
        pruned_type_edges: prune.pruned_type_edges as usize,
        pruned_summaries: prune.pruned_summaries,
        hnsw_rebuilt: false,
        hnsw_vectors: None,
    };
    Ok(serde_json::to_value(&output)?)
}

pub(crate) fn cmd_diff(
    source: &str,
    target: Option<&str>,
    threshold: f32,
    lang: Option<&str>,
    json: bool,
) -> Result<()> {
    let _span = tracing::info_span!("cmd_diff", source).entered();
    let root = find_project_root();
    let cqs_dir = cqs::resolve_index_dir(&root);

    // Resolve source store (must be a reference)
    let source_store = crate::cli::commands::resolve::resolve_reference_store(&root, source)?;

    // Resolve target store
    let target_label = target.unwrap_or("project");
    let target_store = if target_label == "project" {
        let index_path = cqs_dir.join(cqs::INDEX_DB_FILENAME);
        if !index_path.exists() {
            bail!("Project index not found. Run 'cqs init && cqs index' first.");
        }
        Store::open(&index_path)
            .with_context(|| format!("Failed to open project store at {}", index_path.display()))?
    } else {
        crate::cli::commands::resolve::resolve_reference_store(&root, target_label)?
    };

    let result = semantic_diff(
        &source_store,
        &target_store,
        source,
        target_label,
        threshold,
        lang,
    )?;

    if json {
        display_diff_json(&result)?;
    } else {
        display_diff(&result)?;
    }

    Ok(())
}

pub(crate) fn cmd_reconstruct(
    ctx: &crate::cli::CommandContext,
    path: &str,
    json: bool,
) -> Result<()> {
    let _span = tracing::info_span!("cmd_reconstruct", %path).entered();
    let store = &ctx.store;
    let root = &ctx.root;

    // Normalize the path relative to project root
    let rel_path = if std::path::Path::new(path).is_absolute() {
        match std::path::Path::new(path).strip_prefix(root) {
            Ok(rel) => cqs::normalize_path(rel),
            Err(_) => cqs::normalize_path(std::path::Path::new(path)),
        }
    } else {
        cqs::normalize_path(std::path::Path::new(path))
    };

    let chunks = store.get_chunks_by_origin(&rel_path)?;
    if chunks.is_empty() {
        bail!(
            "No indexed chunks found for '{}'. Run `cqs index` first.",
            path
        );
    }

    if json {
        let output = ReconstructOutput {
            file: rel_path.clone(),
            chunks: chunks.len(),
            lines: chunks.last().map(|c| c.line_end).unwrap_or(0),
            content: assemble(&chunks),
        };
        println!("{}", serde_json::to_string_pretty(&output)?);
    } else {
        print!("{}", assemble(&chunks));
    }

    Ok(())
}

pub fn upsert_type_edges_for_file(
        &self,
        file: &Path,
        chunk_type_refs: &[crate::parser::ChunkTypeRefs],
    ) -> Result<(), StoreError> {
        let file_display = file.display().to_string();
        let _span = tracing::info_span!("upsert_type_edges_for_file", file = %file_display, chunks = chunk_type_refs.len()).entered();
        if chunk_type_refs.is_empty() {
            return Ok(());
        }

        let file_str = crate::normalize_path(file);
        let total_refs: usize = chunk_type_refs.iter().map(|c| c.type_refs.len()).sum();
        tracing::trace!(
            file = %file_str,
            chunks = chunk_type_refs.len(),
            total_refs,
            "upserting type edges for file"
        );

        self.rt.block_on(async {
            // DS-14: Begin transaction before reading chunk IDs to prevent TOCTOU
            let (_guard, mut tx) = self.begin_write().await?;
            let inserted = upsert_type_edges_one_file(&mut tx, &file_str, chunk_type_refs).await?;

            if inserted > 0 {
                tracing::info!(
                    file = %file_str,
                    chunks = chunk_type_refs.len(),
                    edges = inserted,
                    "Indexed type edges"
                );
            }
            tx.commit().await?;
            Ok(())
        })
    }

