fn post_process_solidity_solidity(
    name: &mut String,
    chunk_type: &mut ChunkType,
    _node: tree_sitter::Node,
    _source: &str,
) -> bool {
    // constructor() → Constructor
    if matches!(*chunk_type, ChunkType::Function | ChunkType::Method) && name == "constructor" {
        *chunk_type = ChunkType::Constructor;
    }
    // constant state variables → Constant
    if *chunk_type == ChunkType::Property {
        let text = &_source[_node.byte_range()];
        if text.contains("constant ") || text.contains("immutable ") {
            *chunk_type = ChunkType::Constant;
        }
    }
    true
}

impl From<&ChunkIdentity> for ChunkKey {
    /// Converts a ChunkIdentity reference into a ChunkKey.
    ///
    /// This method creates a new ChunkKey by extracting and transforming the relevant fields from a ChunkIdentity. The file path is converted to an owned string, while the name and chunk_type are cloned directly.
    ///
    /// # Arguments
    ///
    /// * `c` - A reference to the ChunkIdentity to convert
    ///
    /// # Returns
    ///
    /// A new ChunkKey containing the origin (file path), name, and chunk_type from the source ChunkIdentity.
    fn from(c: &ChunkIdentity) -> Self {
        ChunkKey {
            origin: c.file.to_string_lossy().into_owned(),
            name: c.name.clone(),
            chunk_type: c.chunk_type,
        }
    }
}

pub fn build(chunks: Vec<(String, SparseVector)>) -> Self {
        let _span = tracing::info_span!("splade_index_build", chunks = chunks.len()).entered();

        let mut postings: HashMap<u32, Vec<(usize, f32)>> = HashMap::new();
        let mut id_map = Vec::with_capacity(chunks.len());

        for (idx, (chunk_id, sparse)) in chunks.into_iter().enumerate() {
            for &(token_id, weight) in &sparse {
                postings.entry(token_id).or_default().push((idx, weight));
            }
            id_map.push(chunk_id);
        }

        tracing::info!(
            unique_tokens = postings.len(),
            chunks = id_map.len(),
            "SPLADE index built"
        );

        Self { postings, id_map }
    }

pub fn get_callers_cross(
        &mut self,
        callee_name: &str,
    ) -> Result<Vec<CrossProjectCaller>, StoreError> {
        let _span = tracing::info_span!(
            "get_callers_cross",
            callee = callee_name,
            projects = self.stores.len()
        )
        .entered();

        self.ensure_all_graphs()?;

        let mut all_callers = Vec::new();
        for (idx, ns) in self.stores.iter().enumerate() {
            let graph = &self.graphs[&idx];
            if let Some(callers) = graph.reverse.get(callee_name) {
                for caller_arc in callers {
                    let caller_name = caller_arc.as_ref();
                    tracing::debug!(
                        project = %ns.name,
                        caller = caller_name,
                        callee = callee_name,
                        "Cross-project caller found"
                    );
                    all_callers.push(CrossProjectCaller {
                        project: ns.name.clone(),
                        caller: CallerInfo {
                            name: caller_name.to_string(),
                            file: std::path::PathBuf::new(),
                            line: 0,
                        },
                    });
                }
            }
        }
        Ok(all_callers)
    }

pub fn call_stats(&self) -> Result<CallStats, StoreError> {
        let _span = tracing::debug_span!("call_stats").entered();
        self.rt.block_on(async {
