    for m in TYPE_HINT_AC.find_overlapping_iter(query) {
        matched[m.pattern().as_usize()] = true;
    }

    let mut types = Vec::new();
    for (idx, (_, chunk_type)) in TYPE_HINT_PATTERNS.iter().enumerate() {
        if matched[idx] {
